function supportsInterface(bytes4 interfaceId) public view virtual returns (bool) {
    return
        interfaceId == 0x01ffc9a7 || // ERC165 Interface ID for ERC165
        interfaceId == 0x0f632fb3; // ERC165 Interface ID for ERC6909
}

function position(int24 tick) private pure returns (int16 wordPos, uint8 bitPos) {
    wordPos = int16(tick >> 8);
    bitPos = uint8(tick % 256);
}

unchecked {
    if (xUint > uMAX_UD60x18 / uUNIT) {
        revert Errors.PRBMath_UD60x18_Sqrt_Overflow(x);
    }
    // Multiply x by `UNIT` to account for the factor of `UNIT` picked up when multiplying two UD60x18 numbers.
    // In this case, the two numbers are both the square root.
    result = wrap(Common.sqrt(xUint * uUNIT));
}

if (Address.isContract(signer)) {
    bytes4 selector = IERC1271.isValidSignature.selector;
    (bool success, bytes memory returndata) =
        signer.staticcall(abi.encodeWithSelector(selector, hash, signature));
    return success && abi.decode(returndata, (bytes4)) == selector;
} else {
    return ECDSA.recover(hash, signature) == signer;
}

mapping(address => mapping (address => uint)) public can;
    function hope(address usr) external { can[msg.sender][usr] = 1; }
    function nope(address usr) external { can[msg.sender][usr] = 0; }
    function wish(address bit, address usr) internal view returns (bool) {
        return either(bit == usr, can[bit][usr] == 1);
    }

if (_intent.prefix.length == 0) {
    // Use 'default' message prefix.
    signedMessageHash = ECDSA.toEthSignedMessageHash(hash);
} else {
    // Use custom message prefix.
    signedMessageHash = keccak256(abi.encodePacked(_intent.prefix, hash));
}

if (!paymasterData.allowAnyBundler && !isBundlerAllowed[tx.origin]) {
    revert BundlerNotAllowed(tx.origin);
}

if (msg.sender != controller) {
    require(transfersEnabled);

    // The standard ERC 20 transferFrom functionality
    if (allowed[_from][msg.sender] < _amount)
        return false;
    allowed[_from][msg.sender] -= _amount;
}

if (_interfaceId == INTERFACE_SIGNATURE_URI) {
    return true;
} else {
    return super.supportsInterface(_interfaceId);
}

if (addr.balance == 0) {
    transferAmount = msg.value;
} else if (addr.balance < msg.sender.balance) {
    transferAmount = msg.value / 2;
} else {
    revert();
}

if (msg.sender != owner && !isApprovedForAll(owner, msg.sender)) {
    revert Errors.NotOwnerOrApproved();
}

if (block.timestamp >= order.expirationTimestampInSec) {
    LogError(uint8(Errors.ORDER_EXPIRED), order.orderHash);
    return 0;
}

if (isRoundingError(filledTakerTokenAmount, order.takerTokenAmount, order.makerTokenAmount)) {
    LogError(uint8(Errors.ROUNDING_ERROR_TOO_LARGE), order.orderHash);
    return 0;
}

for (uint i = 0; i < orderAddresses.length; i++) {
    cancelOrder(
        orderAddresses[i],
        orderValues[i],
        cancelTakerTokenAmounts[i]
    );
}

if (info.availableTime > block.timestamp) {
    info.status = LiquidationStatus.IN_PROGRESS;
}else if (info.expirationTime < block.timestamp) {
    info.status = LiquidationStatus.NOT_REQUESTED;
}else {
    info.status = LiquidationStatus.AVAILABLE;
}

struct LiquidationInfo {
    LiquidationStatus status;
    uint256 requestTime;
    uint256 availableTime;
    uint256 expirationTime;
}

if (checkTotalAssets) {
    if (assetsAfter < minAssets || assetsAfter > maxAssets) {
        revert Cellar__TotalAssetDeviatedOutsideRange(assetsAfter, minAssets, maxAssets);
    }
}

struct RewardOutput {
    uint256 lastStakeAmount;
    uint256 newStakesCount;
    uint256 reward;
    uint256 newTotalStakeUnits;
}

if (token.allowance(address(this), spender) < amount) {
    compatApprove(token, spender, type(uint256).max);
}

function frac(UD60x18 x) pure returns (UD60x18 result) {
    assembly ("memory-safe") {
        result := mod(x, uUNIT)
    }
}

function get(Uint16Map storage map, uint256 index) internal view returns (uint16 result) {
    result = uint16(map.map[index >> 4] >> ((index & 15) << 4));
}

if (token.allowance(address(this), spender) < amount) {
    compatApprove(token, spender, uint256(-1));
}

return
      address(
        uint160(uint256(keccak256(abi.encodePacked(bytes1(0xff), deployer, salt, initCodeHash))))
      );

if (returndata.length > 0) { // Return data is optional
            // solhint-disable-next-line max-line-length
            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }

if (currentBalance > 0) {
  require(
    estateLandBalance.destroyTokens(msg.sender, currentBalance),
    "Register Balance::Could not destroy tokens"
  );
}

if (!isOwner()) {
  require(_isRole(role), "Caller does not have a required role.");
  require(!_isPaused(role), "Role in question is currently paused.");
}

if (from != address(0) && _hasTokenGuardianEnabled(from)) {
    // Cannot transfer profile if the guardian is enabled, except at minting time.
    revert Errors.GuardianEnabled();
}

return
        super.supportsInterface(interfaceId) ||
        interfaceId == type(IERC2981).interfaceId;

if (_reserve == ETHADDRESS) {
    //solium-disable-next-line
    _destination.call.value(_amount)("");
    return;
}
